from typing import List


def _weighted(amount: int, start: int, end: int, qs: int, qe: int) -> float:
    if start > qe or end < qs:
        return 0.0
    duration = end - start
    if duration == 0:
        if qs <= start <= qe:
            return float(amount)
        return 0.0
    overlap_start = max(start, qs)
    overlap_end = min(end, qe)
    overlap_len = overlap_end - overlap_start
    # 按交集占比折算有效量
    return amount * overlap_len / duration


def _round_to_i32(x: float) -> int:
    if x >= 0:
        val = int(x + 0.5)
    else:
        val = int(x - 0.5)
    return max(-2147483648, min(2147483647, val))


class Solution:
    def queryNetEnergy(self, commands: List[str]) -> int:
        qparts = commands[-1].split(",")
        version_str = qparts[1].strip()
        qs, qe = int(qparts[2]), int(qparts[3])
        max_version = 10**9 if version_str == "A" else int(version_str)

        total = 0.0
        version = 0
        for cmd in commands[:-1]:
            version += 1
            if version > max_version:
                break
            parts = cmd.split(",")
            if parts[0] == "AddProductionRecord":
                total += _weighted(int(parts[2]), int(parts[3]), int(parts[4]), qs, qe)
            else:
                total -= _weighted(int(parts[1]), int(parts[2]), int(parts[3]), qs, qe)
        return _round_to_i32(total)
